// Extract the prompt from the request
const input = $input.first().json.body || $input.first().json;

// Prepare data for Claude
const prompt = input.prompt || "What is 2+2?";
const useJson = input.json || false;
const maxTurns = input.max_turns || 1;

return {
  prompt: prompt,
  useJson: useJson,
  maxTurns: maxTurns,
  timestamp: new Date().toISOString()
};

// Parse and format Claude responses
const item = $input.first().json;

let response = {
  success: true,
  timestamp: item.timestamp,
  prompt: item.prompt,
  basic_result: null,
  direct_result: null,
  errors: []
};

// Process basic command result
if (item.stdout) {
  response.basic_result = item.stdout.trim();
}
if (item.stderr) {
  response.errors.push(`Basic: ${item.stderr}`);
}

// Process direct command result
if (item.stdout1) {
  response.direct_result = item.stdout1.trim();
}
if (item.stderr1) {
  response.errors.push(`Direct: ${item.stderr1}`);
}

// Parse JSON if requested
if (item.useJson) {
  try {
    if (response.basic_result) {
      response.basic_result = JSON.parse(response.basic_result);
    }
  } catch (e) {
    response.errors.push(`Failed to parse basic result as JSON: ${e.message}`);
  }

  try {
    if (response.direct_result) {
      response.direct_result = JSON.parse(response.direct_result);
    }
  } catch (e) {
    response.errors.push(`Failed to parse direct result as JSON: ${e.message}`);
  }
}

response.success = response.errors.length === 0;

return response;
